export interface FractalParams {
  centerX: number;
  centerY: number;
  zoom: number;
  maxIterations: number;
  palette: string;
  type: 'mandelbrot' | 'julia';
  juliaC: { r: number; i: number };
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

export type PaletteName = 'fire' | 'ocean' | 'nebula' | 'emerald' | 'monochrome';

export const PALETTES: Record<PaletteName, string[]> = {
  fire: ['#000000', '#420a0a', '#961c1c', '#e14d1a', '#f5b53f', '#ffffff'],
  ocean: ['#000000', '#0a1d42', '#1c4a96', '#1a8ee1', '#3fbaf5', '#ffffff'],
  nebula: ['#000000', '#2d0a42', '#6a1c96', '#a51ae1', '#e43ff5', '#ffffff'],
  emerald: ['#000000', '#0a421d', '#1c964a', '#1ae18e', '#3ff5ba', '#ffffff'],
  monochrome: ['#000000', '#222222', '#555555', '#999999', '#cccccc', '#ffffff']
};

import { GoogleGenAI } from "@google/genai";
import { FractalParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getChaosInsight = async (params: FractalParams) => {
  const prompt = `
    当前的混沌系统参数如下：
    类型: ${params.type}
    坐标: (${params.centerX}, ${params.centerY})
    缩放级别: ${params.zoom}
    迭代深度: ${params.maxIterations}
    ${params.type === 'julia' ? `Julia常量: ${params.juliaC.r} + ${params.juliaC.i}i` : ''}

    请作为一个数学家和诗人，简短地（150字以内）解释这个特定区域体现出的“自相似性”或混沌美学。
    如果坐标在著名的区域（如Mandelbrot的“海马谷”或“大象谷”），请指出。
    请用中文回答，语气优雅且富有启发性。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        temperature: 0.8,
        maxOutputTokens: 300,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "在混沌的边缘，信息的传递受阻。请稍后再试，让数学的灵光再次闪耀。";
  }
};

export const suggestExploration = async (userIntent: string) => {
  const prompt = `
    用户想要探索混沌之境，他们的描述是：“${userIntent}”。
    请返回一个JSON格式的建议参数。
    包含：
    - type: 'mandelbrot' 或 'julia'
    - centerX: 数字
    - centerY: 数字
    - zoom: 数字 (初始建议100-2000)
    - description: 为什么要推荐这个位置的中文描述 (50字以内)

    输出必须是合法的JSON。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

import React, { useRef, useEffect, useCallback } from 'react';
import { FractalParams, PALETTES, PaletteName } from '../types';

interface Props {
  params: FractalParams;
  onUpdateParams: (newParams: Partial<FractalParams>) => void;
}

const FractalCanvas: React.FC<Props> = ({ params, onUpdateParams }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 0, g: 0, b: 0 };
  };

  const getColors = useCallback((paletteName: string) => {
    const colors = PALETTES[paletteName as PaletteName] || PALETTES.nebula;
    return colors.map(hexToRgb);
  }, []);

  const render = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;

    const colors = getColors(params.palette);
    const numColors = colors.length;

    const { centerX, centerY, zoom, maxIterations, type, juliaC } = params;

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx, zy, cx, cy;

        if (type === 'mandelbrot') {
          zx = 0;
          zy = 0;
          cx = (x - width / 2) / zoom + centerX;
          cy = (y - height / 2) / zoom + centerY;
        } else {
          zx = (x - width / 2) / zoom + centerX;
          zy = (y - height / 2) / zoom + centerY;
          cx = juliaC.r;
          cy = juliaC.i;
        }

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < maxIterations) {
          const xtemp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = xtemp;
          i++;
        }

        const pixelIndex = (y * width + x) * 4;
        if (i === maxIterations) {
          data[pixelIndex] = 0;
          data[pixelIndex + 1] = 0;
          data[pixelIndex + 2] = 0;
          data[pixelIndex + 3] = 255;
        } else {
          // Smooth coloring
          const logZn = Math.log(zx * zx + zy * zy) / 2;
          const nu = Math.log(logZn / Math.log(2)) / Math.log(2);
          const iteration = i + 1 - nu;

          const colorIdx = (iteration / maxIterations) * (numColors - 1) * 10;
          const c1 = colors[Math.floor(colorIdx) % numColors];
          const c2 = colors[(Math.floor(colorIdx) + 1) % numColors];
          const f = colorIdx % 1;

          data[pixelIndex] = c1.r + f * (c2.r - c1.r);
          data[pixelIndex + 1] = c1.g + f * (c2.g - c1.g);
          data[pixelIndex + 2] = c1.b + f * (c2.b - c1.b);
          data[pixelIndex + 3] = 255;
        }
      }
    }

    ctx.putImageData(imageData, 0, 0);
  }, [params, getColors]);

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
        render();
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();

    return () => window.removeEventListener('resize', handleResize);
  }, [render]);

  useEffect(() => {
    render();
  }, [render]);

  const handleWheel = (e: React.WheelEvent) => {
    const zoomFactor = e.deltaY < 0 ? 1.1 : 0.9;
    onUpdateParams({ zoom: params.zoom * zoomFactor });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const startX = e.clientX;
    const startY = e.clientY;
    const originalCenterX = params.centerX;
    const originalCenterY = params.centerY;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const dx = (moveEvent.clientX - startX) / params.zoom;
      const dy = (moveEvent.clientY - startY) / params.zoom;
      onUpdateParams({
        centerX: originalCenterX - dx,
        centerY: originalCenterY - dy
      });
    };

    const handleMouseUp = () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <canvas
      ref={canvasRef}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      className="cursor-move w-full h-full"
    />
  );
};

export default FractalCanvas;

