import React, { useState } from 'react';
import { suggestExploration } from '../services/geminiService';
import { FractalParams } from '../types';

interface Props {
  insight: string | null;
  onCloseInsight: () => void;
  onApplyParams: (newParams: Partial<FractalParams>) => void;
}

const AIChatOverlay: React.FC<Props> = ({ insight, onCloseInsight, onApplyParams }) => {
  const [input, setInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setIsSearching(true);
    const suggestion = await suggestExploration(input);
    if (suggestion && suggestion.centerX !== undefined) {
      onApplyParams({
        type: suggestion.type,
        centerX: suggestion.centerX,
        centerY: suggestion.centerY,
        zoom: suggestion.zoom || 500,
      });
      setInput('');
    }
    setIsSearching(false);
  };

  return (
    <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-2xl px-4 pointer-events-none z-50">
      <div className="space-y-4">
        {insight && (
          <div className="glass p-6 rounded-2xl pointer-events-auto animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
            <button 
              onClick={onCloseInsight}
              className="absolute top-2 right-2 text-gray-500 hover:text-white"
            >
              ✕
            </button>
            <div className="flex items-start gap-4">
              <span className="text-2xl">✨</span>
              <div className="space-y-2">
                <h3 className="font-bold text-blue-400 text-sm">AI 深度解读</h3>
                <p className="text-sm leading-relaxed text-gray-200">{insight}</p>
              </div>
            </div>
          </div>
        )}

        <form 
          onSubmit={handleSearch}
          className="glass p-2 rounded-full flex items-center gap-2 pointer-events-auto shadow-2xl ring-1 ring-white/10"
        >
          <input
            type="text"
            placeholder="告诉 AI 你想看什么... (如: '深海恐惧', '宇宙星云', '曼德勃罗的海马谷')"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 py-2"
          />
          <button
            type="submit"
            disabled={isSearching}
            className={`px-6 py-2 rounded-full text-sm font-medium transition-all ${
              isSearching 
              ? 'bg-gray-700 text-gray-400' 
              : 'bg-white text-black hover:bg-blue-500 hover:text-white'
            }`}
          >
            {isSearching ? '构思中...' : '探索'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AIChatOverlay;

import React, { useState, useCallback } from 'react';
import FractalCanvas from './components/FractalCanvas';
import ControlPanel from './components/ControlPanel';
import AIChatOverlay from './components/AIChatOverlay';
import { FractalParams } from './types';
import { getChaosInsight } from './services/geminiService';

const App: React.FC = () => {
  const [params, setParams] = useState<FractalParams>({
    centerX: -0.5,
    centerY: 0,
    zoom: 200,
    maxIterations: 200,
    palette: 'nebula',
    type: 'mandelbrot',
    juliaC: { r: -0.8, i: 0.156 }
  });

  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAILoading, setIsAILoading] = useState(false);

  const updateParams = useCallback((newParams: Partial<FractalParams>) => {
    setParams(prev => ({ ...prev, ...newParams }));
  }, []);

  const handleExplain = async () => {
    setIsAILoading(true);
    const insight = await getChaosInsight(params);
    setAiInsight(insight);
    setIsAILoading(false);
  };

  const handleRandomExploration = () => {
    const isJulia = Math.random() > 0.5;
    const newParams: Partial<FractalParams> = {
      type: isJulia ? 'julia' : 'mandelbrot',
      centerX: (Math.random() - 0.5) * 2,
      centerY: (Math.random() - 0.5) * 2,
      zoom: 150 + Math.random() * 1000,
    };
    if (isJulia) {
      newParams.juliaC = { 
        r: (Math.random() - 0.5) * 1.5, 
        i: (Math.random() - 0.5) * 1.5 
      };
    }
    updateParams(newParams);
    setAiInsight(null);
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-black select-none">
      {/* Fractal Background */}
      <div className="absolute inset-0 z-0">
        <FractalCanvas params={params} onUpdateParams={updateParams} />
      </div>

      {/* UI Overlay */}
      <div className="absolute inset-0 z-10 pointer-events-none flex p-8">
        <div className="flex flex-col h-full">
          <ControlPanel 
            params={params} 
            onUpdateParams={updateParams} 
            onAIEvents={{
              onExplain: handleExplain,
              onRandom: handleRandomExploration
            }}
            isAILoading={isAILoading}
          />
        </div>
      </div>

      {/* AI Assistant Layer */}
      <AIChatOverlay 
        insight={aiInsight} 
        onCloseInsight={() => setAiInsight(null)}
        onApplyParams={updateParams}
      />

      {/* Header Badge */}
      <div className="absolute top-8 right-8 z-10 glass px-4 py-2 rounded-full text-xs font-mono text-gray-400 pointer-events-none">
        Z: {params.zoom.toFixed(1)}x | I: {params.maxIterations}
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useCallback } from 'react';
import { FractalParams, PALETTES, PaletteName } from '../types';

interface Props {
  params: FractalParams;
  onUpdateParams: (newParams: Partial<FractalParams>) => void;
}

const LERP_FACTOR = 0.15; // 追踪速度，数值越大越快（0-1）
const EPSILON = 0.0001;   // 停止动画的阈值

const FractalCanvas: React.FC<Props> = ({ params, onUpdateParams }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(null);

  // 内部维护当前实际渲染的参数，用于实现平滑过渡
  const currentRef = useRef<FractalParams>({ ...params });
  const targetRef = useRef<FractalParams>({ ...params });

  // 辅助函数：十六进制转RGB
  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 0, g: 0, b: 0 };
  };

  const getColors = useCallback((paletteName: string) => {
    const colors = PALETTES[paletteName as PaletteName] || PALETTES.nebula;
    return colors.map(hexToRgb);
  }, []);

  // 线性插值函数
  const lerp = (start: number, end: number, factor: number) => {
    return start + (end - start) * factor;
  };

  const render = useCallback((renderParams: FractalParams) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;

    const colors = getColors(renderParams.palette);
    const numColors = colors.length;

    const { centerX, centerY, zoom, maxIterations, type, juliaC } = renderParams;
    const iterationsInt = Math.floor(maxIterations);

    // 预计算常量提升性能
    const halfW = width / 2;
    const halfH = height / 2;
    const invZoom = 1 / zoom;

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx, zy, cx, cy;

        if (type === 'mandelbrot') {
          zx = 0;
          zy = 0;
          cx = (x - halfW) * invZoom + centerX;
          cy = (y - halfH) * invZoom + centerY;
        } else {
          zx = (x - halfW) * invZoom + centerX;
          zy = (y - halfH) * invZoom + centerY;
          cx = juliaC.r;
          cy = juliaC.i;
        }

        let i = 0;
        let zx2 = zx * zx;
        let zy2 = zy * zy;

        while (zx2 + zy2 < 4 && i < iterationsInt) {
          zy = 2 * zx * zy + cy;
          zx = zx2 - zy2 + cx;
          zx2 = zx * zx;
          zy2 = zy * zy;
          i++;
        }

        const pixelIndex = (y * width + x) * 4;
        if (i === iterationsInt) {
          data[pixelIndex] = 0;
          data[pixelIndex + 1] = 0;
          data[pixelIndex + 2] = 0;
          data[pixelIndex + 3] = 255;
        } else {
          // 平滑着色公式
          const logZn = Math.log(zx2 + zy2) / 2;
          const nu = Math.log(logZn / Math.log(2)) / Math.log(2);
          const iteration = i + 1 - nu;

          const colorIdx = (iteration / iterationsInt) * (numColors - 1) * 10;
          const idx = Math.floor(colorIdx);
          const c1 = colors[idx % numColors];
          const c2 = colors[(idx + 1) % numColors];
          const f = colorIdx % 1;

          data[pixelIndex] = c1.r + f * (c2.r - c1.r);
          data[pixelIndex + 1] = c1.g + f * (c2.g - c1.g);
          data[pixelIndex + 2] = c1.b + f * (c2.b - c1.b);
          data[pixelIndex + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [getColors]);

  const animate = useCallback(() => {
    const curr = currentRef.current;
    const target = targetRef.current;

    // 更新当前参数，向目标参数靠近
    curr.centerX = lerp(curr.centerX, target.centerX, LERP_FACTOR);
    curr.centerY = lerp(curr.centerY, target.centerY, LERP_FACTOR);
    curr.zoom = lerp(curr.zoom, target.zoom, LERP_FACTOR);
    curr.maxIterations = lerp(curr.maxIterations, target.maxIterations, LERP_FACTOR);
    curr.juliaC.r = lerp(curr.juliaC.r, target.juliaC.r, LERP_FACTOR);
    curr.juliaC.i = lerp(curr.juliaC.i, target.juliaC.i, LERP_FACTOR);

    // 处理类型和调色板切换（非数值类型直接同步）
    curr.type = target.type;
    curr.palette = target.palette;

    render(curr);

    // 检查是否需要继续动画
    const dist = Math.abs(curr.centerX - target.centerX) + 
                 Math.abs(curr.zoom - target.zoom) / target.zoom +
                 Math.abs(curr.juliaC.r - target.juliaC.r);

    requestRef.current = requestAnimationFrame(animate);
  }, [render]);

  // 当外部 Props 变化时，仅更新目标，不直接重新渲染
  useEffect(() => {
    targetRef.current = params;
  }, [params]);

  // 初始化动画循环
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        // 为了保持流畅度，可以适当降低 canvas 的分辨率
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [animate]);

  const handleWheel = (e: React.WheelEvent) => {
    const zoomFactor = e.deltaY < 0 ? 1.3 : 0.7; // 增加缩放敏感度以配合平滑效果
    onUpdateParams({ zoom: params.zoom * zoomFactor });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const startX = e.clientX;
    const startY = e.clientY;
    const originalCenterX = params.centerX;
    const originalCenterY = params.centerY;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const dx = (moveEvent.clientX - startX) / params.zoom;
      const dy = (moveEvent.clientY - startY) / params.zoom;
      onUpdateParams({
        centerX: originalCenterX - dx,
        centerY: originalCenterY - dy
      });
    };

    const handleMouseUp = () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <canvas
      ref={canvasRef}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      className="cursor-move w-full h-full"
    />
  );
};

export default FractalCanvas;

export type FractalType = 'mandelbrot' | 'julia' | 'burning_ship' | 'tricorn' | 'multibrot' | 'celtic';

export interface FractalParams {
  centerX: number;
  centerY: number;
  zoom: number;
  maxIterations: number;
  palette: PaletteName;
  type: FractalType;
  juliaC: { r: number; i: number };
}

export type PaletteName = 'aurora' | 'sunset' | 'crystal' | 'forest' | 'midnight';

export const PALETTES: Record<PaletteName, string[]> = {
  aurora: ['#ffffff', '#e0f7fa', '#80deea', '#26c6da', '#00acc1', '#006064'],
  sunset: ['#fffde7', '#fff9c4', '#fff176', '#ffd54f', '#ffb300', '#ff6f00'],
  crystal: ['#f3e5f5', '#e1bee7', '#ce93d8', '#ba68c8', '#ab47bc', '#4a148c'],
  forest: ['#f1f8e9', '#dcedc8', '#aed581', '#7cb342', '#33691e', '#1b5e20'],
  midnight: ['#eceff1', '#cfd8dc', '#90a4ae', '#546e7a', '#263238', '#000000']
};

import React, { useRef, useEffect, useCallback } from 'react';
import { FractalParams, PALETTES, PaletteName, FractalType } from '../types';

interface Props {
  params: FractalParams;
  onUpdateParams: (newParams: Partial<FractalParams>) => void;
}

const LERP_FACTOR = 0.12;

const FractalCanvas: React.FC<Props> = ({ params, onUpdateParams }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(null);
  const currentRef = useRef<FractalParams>({ ...params });
  const targetRef = useRef<FractalParams>({ ...params });

  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 0, g: 0, b: 0 };
  };

  const lerp = (start: number, end: number, factor: number) => start + (end - start) * factor;

  const render = useCallback((p: FractalParams) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    const { width, height } = canvas;
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;
    const colors = PALETTES[p.palette].map(hexToRgb);
    const numColors = colors.length;
    const iterationsInt = Math.floor(p.maxIterations);
    const invZoom = 1 / p.zoom;

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx, zy, cx, cy;

        // 坐标映射
        const mx = (x - width / 2) * invZoom + p.centerX;
        const my = (y - height / 2) * invZoom + p.centerY;

        if (p.type === 'julia') {
          zx = mx; zy = my; cx = p.juliaC.r; cy = p.juliaC.i;
        } else {
          zx = 0; zy = 0; cx = mx; cy = my;
        }

        let i = 0;
        let zx2 = zx * zx;
        let zy2 = zy * zy;

        // 分形迭代逻辑
        while (zx2 + zy2 < 16 && i < iterationsInt) {
          let nextZx, nextZy;

          switch (p.type) {
            case 'burning_ship':
              nextZx = zx2 - zy2 + cx;
              nextZy = Math.abs(2 * zx * zy) + cy;
              zx = Math.abs(nextZx);
              zy = Math.abs(nextZy);
              break;
            case 'tricorn':
              nextZx = zx2 - zy2 + cx;
              nextZy = -2 * zx * zy + cy;
              zx = nextZx; zy = nextZy;
              break;
            case 'multibrot': // z^3 + c
              nextZx = zx * (zx2 - 3 * zy2) + cx;
              nextZy = zy * (3 * zx2 - zy2) + cy;
              zx = nextZx; zy = nextZy;
              break;
            case 'celtic':
              nextZx = Math.abs(zx2 - zy2) + cx;
              nextZy = 2 * zx * zy + cy;
              zx = nextZx; zy = nextZy;
              break;
            default: // mandelbrot / julia
              nextZy = 2 * zx * zy + cy;
              nextZx = zx2 - zy2 + cx;
              zx = nextZx; zy = nextZy;
          }

          zx2 = zx * zx;
          zy2 = zy * zy;
          i++;
        }

        const idx = (y * width + x) * 4;
        if (i === iterationsInt) {
          // 内部区域颜色（浅色主题使用调色板最后一个深色或特定深蓝）
          const innerColor = colors[numColors - 1];
          data[idx] = innerColor.r;
          data[idx + 1] = innerColor.g;
          data[idx + 2] = innerColor.b;
          data[idx + 3] = 255;
        } else {
          // 平滑着色
          const logZn = Math.log(zx2 + zy2) / 2;
          const nu = Math.log(logZn / Math.log(2)) / Math.log(2);
          const iteration = i + 1 - nu;
          const colorPos = (iteration / iterationsInt) * (numColors - 1) * 8;
          const c1 = colors[Math.floor(colorPos) % numColors];
          const c2 = colors[(Math.floor(colorPos) + 1) % numColors];
          const f = colorPos % 1;

          data[idx] = c1.r + f * (c2.r - c1.r);
          data[idx + 1] = c1.g + f * (c2.g - c1.g);
          data[idx + 2] = c1.b + f * (c2.b - c1.b);
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, []);

  const animate = useCallback(() => {
    const curr = currentRef.current;
    const target = targetRef.current;

    curr.centerX = lerp(curr.centerX, target.centerX, LERP_FACTOR);
    curr.centerY = lerp(curr.centerY, target.centerY, LERP_FACTOR);
    curr.zoom = lerp(curr.zoom, target.zoom, LERP_FACTOR);
    curr.maxIterations = lerp(curr.maxIterations, target.maxIterations, LERP_FACTOR);
    curr.juliaC.r = lerp(curr.juliaC.r, target.juliaC.r, LERP_FACTOR);
    curr.juliaC.i = lerp(curr.juliaC.i, target.juliaC.i, LERP_FACTOR);
    curr.type = target.type;
    curr.palette = target.palette;

    render(curr);
    requestRef.current = requestAnimationFrame(animate);
  }, [render]);

  useEffect(() => {
    targetRef.current = params;
  }, [params]);

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [animate]);

  const handleWheel = (e: React.WheelEvent) => {
    const zoomFactor = e.deltaY < 0 ? 1.25 : 0.8;
    onUpdateParams({ zoom: params.zoom * zoomFactor });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const startX = e.clientX;
    const startY = e.clientY;
    const { centerX: ox, centerY: oy, zoom } = params;
    const moveHandler = (me: MouseEvent) => {
      onUpdateParams({
        centerX: ox - (me.clientX - startX) / zoom,
        centerY: oy - (me.clientY - startY) / zoom
      });
    };
    const upHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', upHandler);
    };
    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', upHandler);
  };

  return (
    <canvas ref={canvasRef} onWheel={handleWheel} onMouseDown={handleMouseDown} className="cursor-crosshair w-full h-full" />
  );
};

export default FractalCanvas;

