import React, { useState, useCallback, useEffect } from 'react';
import FractalCanvas from './components/FractalCanvas';
import ControlPanel from './components/ControlPanel';
import AIChatOverlay from './components/AIChatOverlay';
import { FractalParams } from './types';
import { getChaosInsight } from './services/geminiService';

const App: React.FC = () => {
  const [params, setParams] = useState<FractalParams>({
    centerX: -0.75, // 曼德勃罗集的数学均衡中心点
    centerY: 0,
    zoom: 300,
    maxIterations: 400,
    palette: 'aurora',
    type: 'mandelbrot',
    juliaC: { r: -0.7, i: 0.27015 }
  });

  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAILoading, setIsAILoading] = useState(false);

  const updateParams = useCallback((newParams: Partial<FractalParams>) => {
    setParams(prev => ({ ...prev, ...newParams }));
  }, []);

  const handleExplain = async () => {
    setIsAILoading(true);
    const insight = await getChaosInsight(params);
    setAiInsight(insight);
    setIsAILoading(false);
  };

  // 应用启动后自动触发一次 AI 洞察，向用户介绍初始视野
  useEffect(() => {
    const timer = setTimeout(() => {
      handleExplain();
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  const handleRandomExploration = () => {
    const types: FractalParams['type'][] = ['mandelbrot', 'julia', 'burning_ship', 'tricorn', 'multibrot', 'celtic'];
    const randomType = types[Math.floor(Math.random() * types.length)];

    let newParams: Partial<FractalParams> = {
      type: randomType,
      zoom: 300 + Math.random() * 500,
      palette: (['aurora', 'sunset', 'crystal', 'forest'] as const)[Math.floor(Math.random() * 4)]
    };

    if (randomType === 'julia') {
      newParams.centerX = 0;
      newParams.centerY = 0;
      newParams.juliaC = { 
        r: (Math.random() - 0.5) * 1.5, 
        i: (Math.random() - 0.5) * 1.5 
      };
    } else if (randomType === 'mandelbrot') {
      newParams.centerX = -0.75 + (Math.random() - 0.5) * 0.5;
      newParams.centerY = (Math.random() - 0.5) * 0.5;
    } else {
      newParams.centerX = (Math.random() - 0.5) * 0.5;
      newParams.centerY = (Math.random() - 0.5) * 0.5;
    }

    updateParams(newParams);
    // 随机跳转后 800ms 自动触发 AI 解析
    setTimeout(() => handleExplain(), 800);
  };

  const handleReset = () => {
    updateParams({
      centerX: params.type === 'mandelbrot' ? -0.75 : 0,
      centerY: 0,
      zoom: 300
