      {/* 侧边控制台布局 */}
      <div className="absolute inset-0 z-10 pointer-events-none flex p-8 md:p-12">
        <div className="flex flex-col h-full">
          <ControlPanel 
            params={params} 
            onUpdateParams={updateParams} 
            onAIEvents={{
              onExplain: handleExplain,
              onRandom: handleRandomExploration
            }}
            isAILoading={isAILoading}
          />
        </div>
      </div>

      {/* 坐标与导航仪表盘 */}
      <div className="absolute top-10 right-10 z-10 flex flex-col items-end gap-4 pointer-events-none">
        <div className="flex gap-2 pointer-events-auto">
           <button 
             onClick={handleReset}
             className="glass px-5 py-2.5 rounded-2xl text-xs font-bold text-gray-700 hover:text-blue-600 hover:bg-white transition-all shadow-md active:scale-95"
           >
             视野复位
