// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getChaosInsight = async (params: FractalParams) => {
  const prompt = `
    当前的混沌系统参数如下：
    类型: ${params.type}
    坐标: (${params.centerX}, ${params.centerY})
    缩放级别: ${params.zoom}
    迭代深度: ${params.maxIterations}
    ${params.type === 'julia' ? `Julia常量: ${params.juliaC.r} + ${params.juliaC.i}i` : ''}

    请作为一个数学家和诗人，简短地（150字以内）解释这个特定区域体现出的“自相似性”或混沌美学。
    如果坐标在著名的区域（如Mandelbrot的“海马谷”或“大象谷”），请指出。
    请用中文回答，语气优雅且富有启发性。
  `;

  try {
    // Use ai.models.generateContent to query GenAI with the model name and prompt.
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        temperature: 0.8,
      }
    });
    // The response features a text property (not a method) that directly returns the string output.
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "在混沌的边缘，信息的传递受阻。请稍后再试，让数学的灵光再次闪耀。";
  }
};

export const suggestExploration = async (userIntent: string) => {
  const prompt = `
    用户想要探索混沌之境，他们的描述是：“${userIntent}”。
    请提供一个建议的参数对象。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        // The recommended way is to configure a responseSchema for the expected output.
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: {
              type: Type.STRING,
              description: "Fractal type: 'mandelbrot', 'julia', 'burning_ship', 'tricorn', 'multibrot', or 'celtic'.",
            },
            centerX: {
              type: Type.NUMBER,
              description: 'The target X coordinate.',
            },
            centerY: {
              type: Type.NUMBER,
              description: 'The target Y coordinate.',
            },
            zoom: {
              type: Type.NUMBER,
              description: 'The target zoom level (initial suggestion 100-2000).',
            },
            description: {
              type: Type.STRING,
              description: 'A brief Chinese description explaining why this location is recommended.',
            },
          },
          required: ["type", "centerX", "centerY", "zoom", "description"],
          propertyOrdering: ["type", "centerX", "centerY", "zoom", "description"],
        },
      }
    });
    // Extract text output using the .text property
    const jsonStr = response.text?.trim() || '{}';
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

