interface Props {
  insight: string | null;
  onCloseInsight: () => void;
  onApplyParams: (newParams: Partial<SimulationParams>) => void;
}

const AIChatOverlay: React.FC<Props> = ({ insight, onCloseInsight, onApplyParams }) => {
  const [input, setInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setIsSearching(true);
    const suggestion = await suggestExploration(input);
    if (suggestion) {
      onApplyParams(suggestion);
      setInput('');
    }
    setIsSearching(false);
  };

  return (
    <div className="fixed bottom-10 left-1/2 -translate-x-1/2 w-full max-w-3xl px-6 pointer-events-none z-50">
      <div className="space-y-6">
        {insight && (
          <div className="glass p-8 rounded-[32px] pointer-events-auto animate-in fade-in slide-in-from-bottom-8 duration-700 shadow-2xl relative border-indigo-100">
            <button 
              onClick={onCloseInsight}
              className="absolute top-4 right-4 text-slate-300 hover:text-indigo-500 transition-colors"
