    if (params.type === 'hopf') updateParams({ mu: 0.5 });
    if (params.type === 'lorenz') updateParams({ rho: 28 });

    const timer = setTimeout(() => handleExplain(), 2000);
    return () => clearTimeout(timer);
  }, [params.type]);

  const handleReset = () => {
    updateParams({
      mu: 0.5,
      rho: 28,
      speed: 1.0,
      mode: 'auto'
    });
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#f8fafc]">
