import { SimulationParams, AIModelType } from './types';
import { getChaosInsight } from './services/geminiService';

const App: React.FC = () => {
  const [params, setParams] = useState<SimulationParams>({
    type: 'lorenz',
    mode: 'auto',
    mu: 0.5,
    sigma: 10,
    rho: 28,
    beta: 8/3,
    palette: 'neon_lab',
    speed: 1.0
  });

  const [aiModel, setAiModel] = useState<AIModelType>('gemini-3-flash-preview');
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAILoading, setIsAILoading] = useState(false);

  const updateParams = useCallback((newParams: Partial<SimulationParams>) => {
    setParams(prev => ({ ...prev, ...newParams }));
  }, []);

  const handleExplain = async () => {
    setIsAILoading(true);
    const insight = await getChaosInsight(params, aiModel);
    setAiInsight(insight);
    setIsAILoading(false);
  };

  useEffect(() => {
    if (params.type === 'pitchfork') updateParams({ mu: 0.5 });
    if (params.type === 'hopf') updateParams({ mu: 0.5 });
    if (params.type === 'lorenz') updateParams({ rho: 28 });

    const timer = setTimeout(() => handleExplain(), 2000);
    return () => clearTimeout(timer);
  }, [params.type]);

  const handleReset = () => {
    updateParams({
      mu: 0.5,
      rho: 28,
      speed: 1.0,
      mode: 'auto'
    });
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#f8fafc]">
      {/* 仿真背景 */}
      <div className="absolute inset-0 z-0 opacity-80">
        <SimulationCanvas params={params} />
