          <h1 className="text-3xl font-black text-slate-900 tracking-tighter flex items-center gap-4">
            混沌与分岔实验室
            <span className="text-[10px] bg-indigo-50 text-indigo-500 px-3 py-1 rounded-full font-black tracking-widest">BIFURCATION V2</span>
          </h1>
          <p className="text-xs text-slate-500 mt-2 font-medium tracking-wide italic">
            “万物皆流，无物常驻。” —— 赫拉克利特
          </p>
        </div>

        <div className="flex gap-4 pointer-events-auto items-center">
          <div className="glass px-5 py-2.5 rounded-2xl text-[10px] font-mono font-black text-indigo-600 flex items-center gap-3">
             <span className={`w-2 h-2 rounded-full ${params.speed > 0 ? 'bg-green-500 animate-ping' : 'bg-red-500'}`}></span>
             COMPUTING PHASE SPACE
          </div>
          <button onClick={handleReset} className="glass px-6 py-3 rounded-2xl text-xs font-black text-slate-600 hover:bg-white shadow-xl transition-all">起源复位</button>
        </div>
      </div>

      {/* 侧边控制台 */}
      <div className="absolute inset-y-0 left-0 z-10 pointer-events-none flex items-center p-10">
        <ControlPanel 
          params={params} 
          onUpdateParams={updateParams} 
          isAILoading={isAILoading}
        />
      </div>

      {/* 右侧实时监控仪表盘 */}
      <div className="absolute top-40 right-10 z-10 pointer-events-none flex flex-col items-end gap-4">
        <div className="glass px-6 py-4 rounded-3xl pointer-events-auto min-w-[220px]">
          <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3">相点能量密度</h3>
          <div className="flex gap-1 items-end h-8">
            {[...Array(15)].map((_, i) => (
              <div 
                key={i} 
                className="w-full bg-indigo-500/20 rounded-sm" 
                style={{ height: `${20 + Math.random() * 80}%` }}
              />
            ))}
          </div>
        </div>

        <div className="glass px-6 py-4 rounded-3xl pointer-events-auto">
          <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">系统稳定性指数</div>
          <div className="text-xl font-mono font-black text-indigo-600">
            {Math.abs(params.mu * 0.9 + (params.rho/28) * 0.1).toFixed(4)} λ
          </div>
        </div>
      </div>

      {/* 独立 AI 交互模块 */}
      <AIModule 
        insight={aiInsight}
        onCloseInsight={() => setAiInsight(null)}
        onApplyParams={updateParams}
        onTriggerExplain={handleExplain}
        isAILoading={isAILoading}
        currentModel={aiModel}
        onModelChange={setAiModel}
      />

      {/* 底部装饰层 */}
      <div className="absolute bottom-0 left-0 w-full h-32 bg-gradient-to-t from-white/40 to-transparent pointer-events-none z-0"></div>
    </div>
  );
};

