import React, { useRef, useEffect, useCallback } from 'react';
import { SimulationParams, PALETTES } from '../types';

interface Props {
  params: SimulationParams;
}

const SimulationCanvas: React.FC<Props> = ({ params }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particlesRef = useRef<{x: number, y: number, z: number, color: string}[]>([]);
  const requestRef = useRef<number>(null);
  const internalParamsRef = useRef({ ...params });

  // 同步外部参数到内部引用，处理自动模式的微调
  useEffect(() => {
    internalParamsRef.current = { ...params };
  }, [params]);

  // 初始化粒子
  useEffect(() => {
    const particles = [];
    const colors = PALETTES[params.palette];
    const count = params.type === 'lorenz' ? 120 : 180;
    for (let i = 0; i < count; i++) {
      particles.push({
        x: (Math.random() - 0.5) * 4,
        y: (Math.random() - 0.5) * 4,
        z: (Math.random() - 0.5) * 4,
        color: colors[i % colors.length]
      });
    }
    particlesRef.current = particles;
  }, [params.type, params.palette]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const time = Date.now() * 0.001;

    // 自动模式下的参数漂移
    if (params.mode === 'auto') {
      if (params.type === 'lorenz') {
        internalParamsRef.current.rho = params.rho + Math.sin(time * 0.2) * 5;
      } else {
        internalParamsRef.current.mu = params.mu + Math.sin(time * 0.5) * 0.5;
      }
    }

    const currentP = internalParamsRef.current;
    const dt = 0.01 * params.speed;
    const scale = params.type === 'lorenz' ? height / 55 : height / 8;

    ctx.fillStyle = 'rgba(248, 250, 252, 0.08)'; 
    ctx.fillRect(0, 0, width, height);

    particlesRef.current.forEach((p) => {
      let dx = 0, dy = 0, dz = 0;

      if (params.type === 'pitchfork') {
        dx = currentP.mu * p.x - Math.pow(p.x, 3);
        p.x += dx * dt;
        p.y = Math.sin(p.x * 5 + time) * 0.05;
      } else if (params.type === 'hopf') {
        const r = Math.sqrt(p.x * p.x + p.y * p.y);
        const theta = Math.atan2(p.y, p.x);
        const dr = currentP.mu * r - Math.pow(r, 3);
        const dtheta = 1.5;
        const nextR = r + dr * dt;
        const nextTheta = theta + dtheta * dt;
        p.x = nextR * Math.cos(nextTheta);
        p.y = nextR * Math.sin(nextTheta);
      } else if (params.type === 'lorenz') {
        dx = params.sigma * (p.y - p.x);
        dy = p.x * (currentP.rho - p.z) - p.y;
        dz = p.x * p.y - params.beta * p.z;
        p.x += dx * dt;
        p.y += dy * dt;
        p.z += dz * dt;
      }

      const screenX = width / 2 + p.x * scale;
      const screenY = height / 2 - (params.type === 'lorenz' ? (p.z - 25) * scale : p.y * scale);

      ctx.beginPath();
      ctx.arc(screenX, screenY, params.type === 'lorenz' ? 1.2 : 2.5, 0, Math.PI * 2);
      ctx.fillStyle = p.color;
      ctx.fill();
    });

    requestRef.current = requestAnimationFrame(draw);
  }, [params]);

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [draw]);

  return <canvas ref={canvasRef} className="w-full h-full block" />;
};

export default SimulationCanvas;

export type SimulationType = 'pitchfork' | 'hopf' | 'lorenz';
export type SimulationMode = 'auto' | 'manual';
export type AIModelType = 'gemini-3-flash-preview' | 'gemini-3-pro-preview' | 'gemini-2.5-flash-preview-09-2025' | 'deepseek-r1';

export interface SimulationParams {
  type: SimulationType;
  mode: SimulationMode;
  mu: number;       
  sigma: number;    
  rho: number;      
  beta: number;     
  palette: PaletteName;
  speed: number;
}

export type PaletteName = 'neon_lab' | 'deep_river' | 'amber_energy' | 'ghost_white';

export const PALETTES: Record<PaletteName, string[]> = {
  neon_lab: ['#00f2fe', '#4facfe', '#7f00ff', '#e100ff'],
  deep_river: ['#00c6fb', '#005bea', '#00d2ff', '#3a7bd5'],
  amber_energy: ['#f83600', '#f9d423', '#ff9a9e', '#fecfef'],
  ghost_white: ['#f8fafc', '#e2e8f0', '#94a3b8', '#1e293b']
};

import { GoogleGenAI, Type } from "@google/genai";
import { SimulationParams, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getChaosInsight = async (params: SimulationParams, model: AIModelType = 'gemini-3-flash-preview') => {
  // 处理模型回退
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const modelNames = {
    pitchfork: '叉式分岔 (Pitchfork Bifurcation)',
    hopf: '霍普夫分岔 (Hopf Bifurcation)',
    lorenz: '洛伦兹吸引子 (Lorenz Attractor)'
  };

  const prompt = `
    你现在是混沌理论实验室的首席科学家。
    当前实验室正在模拟：${modelNames[params.type]}。
    主要控制参数：${params.type === 'lorenz' ? `ρ=${params.rho}` : `μ=${params.mu}`}。

    请结合“万物皆流”的赫拉克利特哲学，解读当前系统的动力学特征：
    1. 如果是 Pitchfork，谈论对称性破缺与平衡点的诞生。
    2. 如果是 Hopf，谈论从稳态到周期震荡的演化。
    3. 如果是 Lorenz，谈论对初值的极端敏感与奇怪吸引子的哲学。

    要求：中文回答，富有启发性，将数学方程的冷酷转化为生命的流动感，150字以内。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: { temperature: 0.85 }
    });
    return response.text;
  } catch (error) {
    console.error("GenAI Error:", error);
    return "在分岔的临界点，理性暂且缺席。请继续微调参数，观察系统的演化。";
  }
};

export const suggestExploration = async (userIntent: string, model: AIModelType = 'gemini-3-flash-preview') => {
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const prompt = `
    用户想要在实验室中观察特定的物理或哲学意向：${userIntent}。
    请推荐一套微分方程仿真参数。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, description: 'pitchfork, hopf, or lorenz' },
            mu: { type: Type.NUMBER },
            rho: { type: Type.NUMBER },
            description: { type: Type.STRING, description: '为何此参数符合用户意图的简短中文解释' },
          },
          required: ["type", "description"],
        },
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    return null;
  }
};

