import { GoogleGenAI, Type } from "@google/genai";
import { SimulationParams, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getChaosInsight = async (params: SimulationParams, model: AIModelType = 'gemini-3-flash-preview') => {
  // 映射逻辑：DeepSeek R1 在此环境中通过 Gemini 3 Pro 的高性能推理能力模拟
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const modelNames = {
    pitchfork: '叉式分岔 (Pitchfork Bifurcation)',
    hopf: '霍普夫分岔 (Hopf Bifurcation)',
    lorenz: '洛伦兹吸引子 (Lorenz Attractor)'
  };

  const systemInstruction = model === 'deepseek-r1' 
    ? "你现在是深度思考模式下的混沌理论科学家。请在回答前进行深度逻辑分析，展现类似于 DeepSeek R1 的链式推理风格，即使是短回答也要体现深刻的数学逻辑。"
    : "你现在是混沌理论实验室的首席科学家。";

  const prompt = `
    当前实验室正在模拟：${modelNames[params.type]}。
    主要控制参数：${params.type === 'lorenz' ? `ρ=${params.rho}` : `μ=${params.mu}`}。

    请结合“万物皆流”的赫拉克利特哲学，解读当前系统的动力学特征：
    1. 如果是 Pitchfork，谈论对称性破缺与平衡点的诞生。
    2. 如果是 Hopf，谈论从稳态到周期震荡的演化。
    3. 如果是 Lorenz，谈论对初值的极端敏感与奇怪吸引子的哲学。

    要求：中文回答，富有启发性，将数学方程的冷酷转化为生命的流动感，150字以内。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: { 
        systemInstruction,
        temperature: effectiveModel.includes('pro') ? 1.0 : 0.85,
        thinkingConfig: effectiveModel.includes('pro') ? { thinkingBudget: 2000 } : undefined
      }
    });
    return response.text;
  } catch (error) {
    console.error("GenAI Error:", error);
    return "在分岔的临界点，理性暂且缺席。请继续微调参数，观察系统的演变。";
  }
};

export const suggestExploration = async (userIntent: string, model: AIModelType = 'gemini-3-flash-preview') => {
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const prompt = `
    用户想要在实验室中观察特定的物理或哲学意向：${userIntent}。
    请根据此意向推荐一套最适合的仿真模型（pitchfork, hopf, lorenz）及其对应的核心参数。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, description: '仿真模型类型: pitchfork, hopf, or lorenz' },
            mu: { type: Type.NUMBER, description: '用于 pitchfork 或 hopf 的 mu 参数 (-2 to 2)' },
            rho: { type: Type.NUMBER, description: '用于 lorenz 的 rho 参数 (0 to 50)' },
            description: { type: Type.STRING, description: '为何此参数符合用户意图的简短中文解释' },
          },
          required: ["type", "description"],
        },
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Suggestion Error:", error);
    return null;
  }
};

