export const getChaosInsight = async (params: SimulationParams, model: AIModelType = 'gemini-3-flash-preview') => {
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const modelNames = {
    lorenz: '洛伦兹吸引子 (Lorenz Attractor)',
    aizawa: '爱泽吸引子 (Aizawa Attractor)',
    rossler: '罗斯勒吸引子 (Rossler Attractor)',
    thomas: '托马斯吸引子 (Thomas Attractor)'
  };

  const systemInstruction = model === 'deepseek-r1' 
    ? "你现在是深度思考模式下的非线性动力学专家。请在回答前进行深度逻辑分析，展现类似于 DeepSeek R1 的链式推理风格，即使是短回答也要体现深刻的数学逻辑。"
    : "你现在是混沌实验室的首席动力学顾问。";

  const prompt = `
    当前实验室模拟：${modelNames[params.type]}。
    核心参数：λ=${params.type === 'thomas' ? params.mu : (params.type === 'aizawa' ? params.mu : params.rho)}。

    请结合非线性动力学与艺术哲学，解读该系统的美学与物理意义：
    1. Aizawa: 讨论有机形态与复杂性宝石。
    2. Rossler: 讨论简单的折叠如何产生无限的层级。
    3. Thomas: 讨论对称性与迷宫状混沌。
    4. Lorenz: 讨论蝴蝶效应与预测的终点。

    中文回答，富有启发性，120字以内。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: { 
        systemInstruction,
        temperature: 0.9,
        thinkingConfig: effectiveModel.includes('pro') ? { thinkingBudget: 1500 } : undefined
      }
    });
    return response.text;
  } catch (error) {
    return "在相空间的缠绕中，我们瞥见了秩序的阴影。";
  }
};

export const suggestExploration = async (userIntent: string, model: AIModelType = 'gemini-3-flash-preview') => {
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const prompt = `
    用户意图：${userIntent}。
