import React from 'react';
import { SimulationParams, PaletteName, PALETTES, SimulationType } from '../types';

interface Props {
  params: SimulationParams;
  onUpdateParams: (newParams: Partial<SimulationParams>) => void;
  isAILoading: boolean;
}

const ControlPanel: React.FC<Props> = ({ params, onUpdateParams, isAILoading }) => {
  const models: { id: SimulationType; label: string; desc: string }[] = [
    { id: 'lorenz', label: '洛伦兹', desc: '经典双翼/蝴蝶效应' },
    { id: 'aizawa', label: '爱泽', desc: '球形几何/珠宝美学' },
    { id: 'dadras', label: '达德拉斯', desc: '四翼对称/星团混沌' },
    { id: 'thomas', label: '托马斯', desc: '环形迷宫/对称晶格' },
  ];

  return (
    <div className="glass rounded-[40px] p-8 w-[400px] space-y-8 pointer-events-auto border-white/40 shadow-2xl">
      <div className="space-y-4">
        <div className="flex justify-between items-end">
          <h2 className="text-[15px] font-black text-indigo-500 uppercase tracking-widest">推演模式控制</h2>
          <div className="flex bg-slate-100 p-1 rounded-xl">
             <button 
               onClick={() => onUpdateParams({ mode: 'manual' })}
               className={`px-3 py-1.5 rounded-lg text-[15px] font-bold transition-all ${params.mode === 'manual' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
             >
               手动
             </button>
             <button 
               onClick={() => onUpdateParams({ mode: 'auto' })}
               className={`px-3 py-1.5 rounded-lg text-[15px] font-bold transition-all ${params.mode === 'auto' ? 'bg-indigo-600 shadow-sm text-white' : 'text-slate-400'}`}
             >
               智能
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-2">
          {models.map((m) => (
            <button
              key={m.id}
              onClick={() => onUpdateParams({ type: m.id })}
              className={`w-full p-4 rounded-2xl text-left transition-all border-2 group ${
                params.type === m.id 
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                  : 'bg-white/40 border-transparent hover:border-indigo-100 text-slate-600'
              }`}
            >
              <div className="font-black text-xl">{m.label}吸引子</div>
              <div className={`text-[15px] ${params.type === m.id ? 'text-indigo-100' : 'text-slate-400'}`}>{m.desc}</div>
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-6">
        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-[15px] font-black text-slate-400 uppercase tracking-widest">
              混沌核心参数 (λ)
            </label>
            <span className={`text-base font-mono font-bold ${params.mode === 'auto' ? 'text-teal-500 animate-pulse' : 'text-indigo-600'}`}>
              {params.type === 'lorenz' ? params.rho.toFixed(2) : (params.type === 'thomas' ? params.mu.toFixed(4) : params.mu.toFixed(2))}
            </span>
          </div>
          <input 
            type="range"
            min={params.type === 'thomas' ? "0.05" : (params.type === 'lorenz' ? "1" : "1")}
            max={params.type === 'thomas' ? "0.4" : (params.type === 'lorenz' ? "50" : "10")}
            step="0.0001"
            disabled={params.mode === 'auto'}
            value={params.type === 'lorenz' ? params.rho : params.mu}
            onChange={(e) => {
                const val = parseFloat(e.target.value);
                if (params.type === 'lorenz') onUpdateParams({ rho: val });
                else onUpdateParams({ mu: val });
            }}
            className={`w-full accent-indigo-600 ${params.mode === 'auto' ? 'opacity-30 cursor-not-allowed' : ''}`}
          />
        </div>

        <div className="pt-6 border-t border-slate-100/50">
          <label className="text-[15px] font-black text-slate-400 uppercase mb-3 block">色彩能谱</label>
          <div className="flex gap-3">
            {(Object.keys(PALETTES) as PaletteName[]).map((p) => (
              <button
                key={p}
                onClick={() => onUpdateParams({ palette: p })}
                className={`w-12 h-12 rounded-xl border-2 transition-all p-1 ${
                  params.palette === p ? 'border-indigo-500 scale-110 shadow-md' : 'border-transparent opacity-60 hover:opacity-100'
                }`}
              >
                <div 
                  className="w-full h-full rounded-lg" 
                  style={{ background: `linear-gradient(135deg, ${PALETTES[p][0]}, ${PALETTES[p][1]})` }}
                />
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useState } from 'react';
import { suggestExploration } from '../services/geminiService';
import { SimulationParams, AIModelType } from '../types';

interface Props {
  insight: string | null;
  onCloseInsight: () => void;
  onApplyParams: (newParams: Partial<SimulationParams>) => void;
  onTriggerExplain: () => void;
  isAILoading: boolean;
  currentModel: AIModelType;
  onModelChange: (model: AIModelType) => void;
}

const AIModule: React.FC<Props> = ({ 
  insight, 
  onCloseInsight, 
  onApplyParams, 
  onTriggerExplain, 
  isAILoading,
  currentModel,
  onModelChange 
}) => {
  const [input, setInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    setIsSearching(true);
    const suggestion = await suggestExploration(input, currentModel);
    if (suggestion) {
      onApplyParams(suggestion);
      setInput('');
    }
    setIsSearching(false);
  };

  const handleOpenKeySelection = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setShowSettings(false);
    } else {
      alert('当前运行环境不支持手动配置 API 密钥。');
    }
  };

  const modelOptions: { id: AIModelType; label: string; sub: string }[] = [
    { id: 'gemini-3-flash-preview', label: 'Gemini 3 Flash', sub: '极致速度 · 实时响应' },
    { id: 'gemini-3-pro-preview', label: 'Gemini 3 Pro', sub: '深度推理 · 科学洞察' },
    { id: 'gemini-2.5-flash-preview-09-2025', label: 'Gemini 2.5 Flash', sub: '稳定长文 · 上下文优化' },
    { id: 'deepseek-r1', label: 'DeepSeek R1', sub: '链式思考 · 逻辑推演' },
  ];

  return (
    <div className="w-full flex flex-col">
      <div className="w-full bg-slate-50 border-t border-slate-200">

        {/* 1. 状态指示与模型切换器 */}
        <div className="px-12 py-5 border-b border-slate-200/60 flex justify-between items-center bg-white/40">
          <div className="flex items-center gap-4">
            <div className="relative flex h-4 w-4">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-4 w-4 bg-indigo-600"></span>
            </div>
            <div className="flex flex-col">
              <span className="text-[17px] font-black text-slate-800 uppercase tracking-[0.2em] leading-none">智慧决策中枢</span>
              <span className="text-[14px] text-slate-400 font-bold mt-1">CURRENT ENGINE: {currentModel.toUpperCase()}</span>
            </div>
          </div>

          <div className="relative">
            <button 
              onClick={() => setShowSettings(!showSettings)}
              className={`flex items-center gap-3 px-5 py-2.5 rounded-2xl border transition-all ${
                showSettings 
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' 
                  : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300 hover:shadow-lg'
              }`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 transition-transform duration-500 ${showSettings ? 'rotate-90' : ''}`} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="3"></circle>
                <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"></path>
              </svg>
              <span className="text-[17px] font-black uppercase tracking-wider">内核管理</span>
            </button>

            {showSettings && (
              <div className="absolute right-0 bottom-full mb-4 bg-white p-6 rounded-[32px] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.15)] border border-slate-100 min-w-[360px] z-[100] animate-in fade-in slide-in-from-bottom-6 duration-300">
                <div className="space-y-6">
                  <div>
                    <h4 className="text-[15px] font-black text-slate-400 uppercase tracking-widest mb-4 px-1">核心推演引擎</h4>
                    <div className="grid grid-cols-1 gap-2.5">
                      {modelOptions.map((opt) => (
                        <button 
                          key={opt.id}
                          onClick={() => { onModelChange(opt.id); }}
                          className={`w-full text-left px-5 py-3.5 rounded-2xl transition-all border-2 ${
                            currentModel === opt.id 
                              ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                              : 'bg-slate-50 border-transparent text-slate-600 hover:bg-indigo-50 hover:text-indigo-600'
                          }`}
                        >
                          <div className="flex justify-between items-center mb-0.5">
                            <span className="text-xl font-black">{opt.label}</span>
                            {currentModel === opt.id && <span className="text-[12px] bg-white/20 px-2 py-0.5 rounded-full uppercase font-bold tracking-tighter">Active</span>}
                          </div>
                          <div className={`text-[15px] opacity-70 font-medium ${currentModel === opt.id ? 'text-indigo-100' : 'text-slate-400'}`}>{opt.sub}</div>
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="pt-5 border-t border-slate-100">
                    <h4 className="text-[15px] font-black text-slate-400 uppercase tracking-widest mb-4 px-1">安全访问令牌</h4>
                    <div className="space-y-4 px-1">
                      <p className="text-[15px] text-slate-400 leading-relaxed italic">
                        实验室采用严格的安全注入协议，API 密钥将通过官方授权对话框进行管理，系统不直接存储任何明文密钥。
                      </p>
                      <button 
                        onClick={handleOpenKeySelection}
                        className="w-full py-4 px-5 rounded-2xl bg-slate-900 text-white text-[17px] font-black uppercase tracking-[0.2em] hover:bg-black transition-all flex items-center justify-center gap-3 shadow-xl active:scale-[0.98]"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M2.166 4.999A11.954 11.954 0 0010 1.944 11.954 11.954 0 0017.834 5c.11.65.166 1.32.166 2.001 0 5.225-3.34 9.67-8 11.317C5.34 16.67 2 12.225 2 7c0-.682.057-1.35.166-2.001zm11.541 3.708a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                        配置实验室访问权限
                      </button>
                      <div className="text-center pt-1">
                        <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-[14px] text-indigo-500 font-bold underline decoration-indigo-200 hover:text-indigo-700">获取开发者支持</a>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* 2. 实时报告区 (仅在有洞察结果时显示) */}
        {insight && (
          <div className="px-12 py-10 bg-indigo-50/20 border-b border-indigo-100/30 relative animate-in fade-in slide-in-from-top-4 duration-700">
            <button 
              onClick={onCloseInsight}
              className="absolute top-8 right-12 text-slate-300 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-white/50 shadow-sm"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
            <div className="flex gap-12 items-start max-w-7xl mx-auto">
              <div className="bg-white p-5 rounded-3xl shadow-[0_8px_30px_rgba(0,0,0,0.04)] text-6xl border border-indigo-50/50 shrink-0 select-none animate-bounce-subtle">✨</div>
              <div className="space-y-4">
                <h4 className="text-[15px] font-black text-indigo-400 uppercase tracking-[0.3em]">AI 实时推演报告</h4>
                <p className="text-[27px] leading-[1.7] text-slate-800 font-medium italic font-serif">“{insight}”</p>
                <div className="flex gap-3">
                  <span className="h-1.5 w-18 bg-indigo-200 rounded-full"></span>
                  <span className="h-1.5 w-6 bg-indigo-100 rounded-full"></span>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* 3. 核心交互输入区 */}
        <div className="p-12 bg-white">
          <div className="max-w-7xl mx-auto flex gap-10 items-center w-full">
            <form 
              onSubmit={handleSearch}
              className="flex-1 bg-slate-50/80 hover:bg-white rounded-[35px] flex items-center gap-3 pr-3 border border-slate-200/60 shadow-inner ring-1 ring-transparent focus-within:ring-indigo-100 focus-within:border-indigo-300 transition-all duration-300"
            >
              <div className="pl-8 text-indigo-500 py-6">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
              <input
                type="text"
                placeholder="尝试输入：'分析当前系统的稳定性极限' 或 '模拟类似于生命搏动的混沌律动'..."
                value={input}
                onChange={(e) => setInput(e.target.value)}
                className="flex-1 bg-transparent border-none focus:ring-0 text-2xl py-5 px-2 text-slate-700 font-bold placeholder:text-slate-400 placeholder:font-medium"
              />
              <button
                type="submit"
                disabled={isSearching}
                className={`px-12 py-4 rounded-[28px] text-[20px] font-black transition-all ${
                  isSearching 
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-2xl shadow-indigo-500/30 active:scale-95'
                }`}
              >
                {isSearching ? '推演中...' : '提交指令'}
              </button>
            </form>

            <button
              onClick={onTriggerExplain}
              disabled={isAILoading}
              className={`h-24 w-24 rounded-[35px] flex items-center justify-center bg-white border border-slate-100 shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] transition-all shrink-0 ${
                isAILoading ? 'opacity-50 cursor-not-allowed' : 'hover:scale-110 active:scale-90 hover:bg-indigo-50 hover:border-indigo-100 text-slate-700 hover:text-indigo-600'
              }`}
              title="即时生成动力学洞察"
            >
              <div className={`text-6xl transition-all duration-1000 ${isAILoading ? 'animate-spin' : ''}`}>
                {isAILoading ? '⚛' : '🧠'}
              </div>
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AIModule;

