/**
 * 建议探索参数（保持 JSON 格式返回）
 */
export const suggestExploration = async (userIntent: string, model: AIModelType = 'gemini-3-flash-preview') => {
  const effectiveModel = model === 'deepseek-r1' ? 'gemini-3-pro-preview' : model;

  const prompt = `
    用户意图：${userIntent}。
    请推荐一个吸引子（lorenz, aizawa, dadras, thomas）及参数。
    请仅返回 JSON。
  `;

  try {
    const response = await ai.models.generateContent({
      model: effectiveModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, description: 'lorenz, aizawa, dadras, or thomas' },
            mu: { type: Type.NUMBER },
            rho: { type: Type.NUMBER },
            description: { type: Type.STRING },
          },
          required: ["type", "description"],
        },
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    return null;
  }
};

