export type SimulationType = 'lorenz' | 'aizawa' | 'dadras' | 'thomas' | 'halvorsen';
export type SimulationMode = 'auto' | 'manual';
export type AIModelType = 'gemini-3-flash-preview' | 'gemini-3-pro-preview' | 'gemini-2.5-flash-preview-09-2025' | 'deepseek-r1';

export interface SimulationParams {
  type: SimulationType;
  mode: SimulationMode;
  mu: number;       // 通用控制变量
  sigma: number;    
  rho: number;      
  beta: number;     
  palette: PaletteName;
  speed: number;
}

export type PaletteName = 'neon_lab' | 'deep_river' | 'amber_energy' | 'ghost_white';

export const PALETTES: Record<PaletteName, string[]> = {
  neon_lab: ['#00f2fe', '#4facfe', '#7f00ff', '#e100ff'],
  deep_river: ['#00c6fb', '#005bea', '#00d2ff', '#3a7bd5'],
  amber_energy: ['#f83600', '#f9d423', '#ff9a9e', '#fecfef'],
  ghost_white: ['#f8fafc', '#e2e8f0', '#94a3b8', '#1e293b']
};

import React, { useRef, useEffect, useCallback } from 'react';
import { SimulationParams, PALETTES } from '../types';

interface Props {
  params: SimulationParams;
}

const SimulationCanvas: React.FC<Props> = ({ params }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particlesRef = useRef<{x: number, y: number, z: number, color: string}[]>([]);
  const requestRef = useRef<number>(null);
  const internalParamsRef = useRef({ ...params });

  // 交互状态：旋转角度与鼠标轨迹
  const rotationRef = useRef({ x: 0, y: 0 });
  const isDraggingRef = useRef(false);
  const lastMouseRef = useRef({ x: 0, y: 0 });

  useEffect(() => {
    internalParamsRef.current = { ...params };
  }, [params]);

  useEffect(() => {
    const particles = [];
    const colors = PALETTES[params.palette];
    const count = 400; // 增加粒子密度以增强 3D 效果
    for (let i = 0; i < count; i++) {
      particles.push({
        x: (Math.random() - 0.5) * 2,
        y: (Math.random() - 0.5) * 2,
        z: (Math.random() - 0.5) * 2,
        color: colors[i % colors.length]
      });
    }
    particlesRef.current = particles;
  }, [params.type, params.palette]);

  const handleMouseDown = (e: React.MouseEvent) => {
    isDraggingRef.current = true;
    lastMouseRef.current = { x: e.clientX, y: e.clientY };
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDraggingRef.current) return;
    const dx = e.clientX - lastMouseRef.current.x;
    const dy = e.clientY - lastMouseRef.current.y;
    rotationRef.current.y += dx * 0.01;
    rotationRef.current.x += dy * 0.01;
    lastMouseRef.current = { x: e.clientX, y: e.clientY };
  };

  const handleMouseUp = () => {
    isDraggingRef.current = false;
  };

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const time = Date.now() * 0.001;

    if (params.mode === 'auto') {
      if (params.type === 'lorenz') internalParamsRef.current.rho = 28 + Math.sin(time * 0.3) * 10;
      if (params.type === 'aizawa') internalParamsRef.current.mu = 0.35 + Math.sin(time * 0.2) * 0.1;
      if (params.type === 'dadras') internalParamsRef.current.mu = 3.0 + Math.sin(time * 0.4) * 0.5;
      if (params.type === 'thomas') internalParamsRef.current.mu = 0.2081 + Math.sin(time * 0.4) * 0.05;
      if (params.type === 'halvorsen') internalParamsRef.current.mu = 1.89 + Math.sin(time * 0.3) * 0.2;

      if (!isDraggingRef.current) {
        rotationRef.current.y += 0.005; // 自动缓慢旋转
      }
    }

    const currentP = internalParamsRef.current;
    const dt = 0.015 * params.speed;

    ctx.fillStyle = 'rgba(248, 250, 252, 0.15)'; 
    ctx.fillRect(0, 0, width, height);

    const cosY = Math.cos(rotationRef.current.y);
    const sinY = Math.sin(rotationRef.current.y);
    const cosX = Math.cos(rotationRef.current.x);
    const sinX = Math.sin(rotationRef.current.x);

    particlesRef.current.forEach((p) => {
      let dx = 0, dy = 0, dz = 0;

      if (params.type === 'lorenz') {
        dx = 10 * (p.y - p.x);
        dy = p.x * (currentP.rho - p.z) - p.y;
        dz = p.x * p.y - (8/3) * p.z;
      } else if (params.type === 'aizawa') {
        const a = 0.95, b = 0.7, c = 0.6, d = 3.5, e = 0.25, f = 0.1;
        dx = (p.z - b) * p.x - d * p.y;
        dy = d * p.x + (p.z - b) * p.y;
        dz = c + a * p.z - (Math.pow(p.z, 3) / 3) - (p.x * p.x + p.y * p.y) * (1 + e * p.z) + f * p.z * Math.pow(p.x, 3);
      } else if (params.type === 'dadras') {
        const a = 3, b = 2.7, c = 1.7, d = 2, e = 9;
        dx = p.y - a * p.x + b * p.y * p.z;
        dy = c * p.y - p.x * p.z + p.z;
        dz = d * p.x * p.y - e * p.z;
      } else if (params.type === 'thomas') {
        const b = currentP.mu;
        dx = Math.sin(p.y) - b * p.x;
        dy = Math.sin(p.z) - b * p.y;
        dz = Math.sin(p.x) - b * p.z;
      } else if (params.type === 'halvorsen') {
        const a = currentP.mu;
        dx = -a * p.x - 4 * p.y - 4 * p.z - p.y * p.y;
        dy = -a * p.y - 4 * p.z - 4 * p.x - p.z * p.z;
        dz = -a * p.z - 4 * p.x - 4 * p.y - p.x * p.x;
      }

      p.x += dx * dt;
      p.y += dy * dt;
      p.z += dz * dt;

      // 3D 变换
      let tx = p.x * cosY - p.z * sinY;
      let tz = p.x * sinY + p.z * cosY;
      let ty = p.y * cosX - tz * sinX;
      let finalZ = p.y * sinX + tz * cosX;

      let scale = height / 60;
      let offsetX = width / 2;
      let offsetY = height / 2;

      if (params.type === 'aizawa') scale = height / 4.5;
      else if (params.type === 'dadras') scale = height / 22;
      else if (params.type === 'thomas') scale = height / 12;
      else if (params.type === 'halvorsen') scale = height / 18;
      else if (params.type === 'lorenz') scale = height / 70;

      const screenX = offsetX + tx * scale;
      const screenY = offsetY - ty * scale;

      const depthAlpha = Math.max(0.2, (finalZ + 25) / 50);
      const dotSize = Math.max(0.6, 1.4 * depthAlpha);

      ctx.beginPath();
      ctx.arc(screenX, screenY, dotSize, 0, Math.PI * 2);
      ctx.globalAlpha = depthAlpha;
      ctx.fillStyle = p.color;
      ctx.fill();
      ctx.globalAlpha = 1.0;
    });

    requestRef.current = requestAnimationFrame(draw);
  }, [params]);

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [draw]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full block cursor-move active:cursor-grabbing" 
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    />
  );
};

export default SimulationCanvas;

