export interface SimulationParams {
  type: SimulationType;
  mode: SimulationMode;
  mu: number;       // 通用控制变量
  sigma: number;    
  rho: number;      
  beta: number;     
  palette: PaletteName;
  speed: number;
  showTrace: boolean; // 新增：是否显示单个粒子的长期轨迹
}

export type PaletteName = 'neon_lab' | 'deep_river' | 'amber_energy' | 'ghost_white';

