interface Props {
  params: SimulationParams;
  onUpdateParams: (newParams: Partial<SimulationParams>) => void;
  isAILoading: boolean;
}

const ControlPanel: React.FC<Props> = ({ params, onUpdateParams, isAILoading }) => {
  const models: { id: SimulationType; label: string; desc: string }[] = [
    { id: 'lorenz', label: '洛伦兹', desc: '经典双翼/蝴蝶效应' },
    { id: 'aizawa', label: '爱泽', desc: '球形几何/珠宝美学' },
    { id: 'dadras', label: '达德拉斯', desc: '四翼对称/星团混沌' },
    { id: 'thomas', label: '托马斯', desc: '环形迷宫/对称晶格' },
  ];

  return (
    <div className="glass rounded-[40px] p-8 w-[340px] space-y-8 pointer-events-auto border-white/40 shadow-2xl">
      <div className="space-y-4">
        <div className="flex justify-between items-end">
          <h2 className="text-[10px] font-black text-indigo-500 uppercase tracking-widest">推演模式控制</h2>
          <div className="flex bg-slate-100 p-1 rounded-xl">
             <button 
               onClick={() => onUpdateParams({ mode: 'manual' })}
               className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${params.mode === 'manual' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
             >
               手动
             </button>
             <button 
               onClick={() => onUpdateParams({ mode: 'auto' })}
               className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${params.mode === 'auto' ? 'bg-indigo-600 shadow-sm text-white' : 'text-slate-400'}`}
             >
               智能
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-2">
          {models.map((m) => (
            <button
              key={m.id}
              onClick={() => onUpdateParams({ type: m.id })}
              className={`w-full p-4 rounded-2xl text-left transition-all border-2 group ${
                params.type === m.id 
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                  : 'bg-white/40 border-transparent hover:border-indigo-100 text-slate-600'
              }`}
            >
              <div className="font-black text-sm">{m.label}吸引子</div>
              <div className={`text-[10px] ${params.type === m.id ? 'text-indigo-100' : 'text-slate-400'}`}>{m.desc}</div>
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-6">
        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
              混沌核心参数 (λ)
            </label>
            <span className={`text-xs font-mono font-bold ${params.mode === 'auto' ? 'text-teal-500 animate-pulse' : 'text-indigo-600'}`}>
              {params.type === 'lorenz' ? params.rho.toFixed(2) : (params.type === 'thomas' ? params.mu.toFixed(4) : params.mu.toFixed(2))}
            </span>
          </div>
          <input 
            type="range"
            min={params.type === 'thomas' ? "0.05" : (params.type === 'lorenz' ? "1" : "1")}
            max={params.type === 'thomas' ? "0.4" : (params.type === 'lorenz' ? "50" : "10")}
            step="0.0001"
            disabled={params.mode === 'auto'}
            value={params.type === 'lorenz' ? params.rho : params.mu}
            onChange={(e) => {
                const val = parseFloat(e.target.value);
                if (params.type === 'lorenz') onUpdateParams({ rho: val });
                else onUpdateParams({ mu: val });
            }}
            className={`w-full accent-indigo-600 ${params.mode === 'auto' ? 'opacity-30 cursor-not-allowed' : ''}`}
          />
        </div>

        <div className="flex items-center justify-between pt-4">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">路径追踪可视化</label>
          <button 
            onClick={() => onUpdateParams({ showTrace: !params.showTrace })}
            className={`w-12 h-6 rounded-full transition-all relative ${params.showTrace ? 'bg-indigo-600' : 'bg-slate-200'}`}
          >
            <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${params.showTrace ? 'left-7' : 'left-1'}`} />
          </button>
        </div>

        <div className="pt-6 border-t border-slate-100/50">
          <label className="text-[10px] font-black text-slate-400 uppercase mb-3 block">色彩能谱</label>
          <div className="flex gap-3">
            {(Object.keys(PALETTES) as PaletteName[]).map((p) => (
              <button
                key={p}
                onClick={() => onUpdateParams({ palette: p })}
                className={`w-10 h-10 rounded-xl border-2 transition-all p-1 ${
                  params.palette === p ? 'border-indigo-500 scale-110 shadow-md' : 'border-transparent opacity-60 hover:opacity-100'
                }`}
              >
                <div 
                  className="w-full h-full rounded-lg" 
                  style={{ background: `linear-gradient(135deg, ${PALETTES[p][0]}, ${PALETTES[p][1]})` }}
                />
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useRef, useEffect, useCallback } from 'react';
import { SimulationParams, PALETTES } from '../types';

interface Props {
  params: SimulationParams;
}

const SimulationCanvas: React.FC<Props> = ({ params }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particlesRef = useRef<{x: number, y: number, z: number, color: string}[]>([]);
  const pathRef = useRef<{x: number, y: number, z: number}[]>([]); // 存储主粒子的历史轨迹
  const requestRef = useRef<number>(null);
  const internalParamsRef = useRef({ ...params });

  useEffect(() => {
    internalParamsRef.current = { ...params };
  }, [params]);

  useEffect(() => {
    const particles = [];
    const colors = PALETTES[params.palette];
    const count = 300; 
    for (let i = 0; i < count; i++) {
      particles.push({
        x: (Math.random() - 0.5) * 1.1,
        y: (Math.random() - 0.5) * 1.1,
        z: (Math.random() - 0.5) * 1.1 + (params.type === 'aizawa' ? 0.1 : 0),
        color: colors[i % colors.length]
      });
    }
    particlesRef.current = particles;
    pathRef.current = []; // 切换类型时清空路径
  }, [params.type, params.palette]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const time = Date.now() * 0.001;

    if (params.mode === 'auto') {
      if (params.type === 'lorenz') internalParamsRef.current.rho = 28 + Math.sin(time * 0.3) * 10;
      if (params.type === 'aizawa') internalParamsRef.current.mu = 0.35 + Math.sin(time * 0.2) * 0.1;
      if (params.type === 'dadras') internalParamsRef.current.mu = 3.0 + Math.sin(time * 0.4) * 0.5;
      if (params.type === 'thomas') internalParamsRef.current.mu = 0.2081 + Math.sin(time * 0.4) * 0.05;
    }

    const currentP = internalParamsRef.current;
    const dt = 0.015 * params.speed;

    // 背景淡入淡出实现拖尾效果
    ctx.fillStyle = 'rgba(248, 250, 252, 0.15)'; 
    ctx.fillRect(0, 0, width, height);

    let leadScreenPoints: {x: number, y: number}[] = [];

    particlesRef.current.forEach((p, idx) => {
      let dx = 0, dy = 0, dz = 0;

      if (params.type === 'lorenz') {
        dx = 10 * (p.y - p.x);
        dy = p.x * (currentP.rho - p.z) - p.y;
        dz = p.x * p.y - (8/3) * p.z;
      } else if (params.type === 'aizawa') {
        const a = 0.95, b = 0.7, c = 0.6, d = 3.5, e = 0.25, f = 0.1;
        dx = (p.z - b) * p.x - d * p.y;
        dy = d * p.x + (p.z - b) * p.y;
        dz = c + a * p.z - (Math.pow(p.z, 3) / 3) - (p.x * p.x + p.y * p.y) * (1 + e * p.z) + f * p.z * Math.pow(p.x, 3);
      } else if (params.type === 'dadras') {
        const a = 3, b = 2.7, c = 1.7, d = 2, e = 9;
        dx = p.y - a * p.x + b * p.y * p.z;
        dy = c * p.y - p.x * p.z + p.z;
        dz = d * p.x * p.y - e * p.z;
      } else if (params.type === 'thomas') {
        const b = currentP.mu;
        dx = Math.sin(p.y) - b * p.x;
        dy = Math.sin(p.z) - b * p.y;
        dz = Math.sin(p.x) - b * p.z;
      }

      p.x += dx * dt;
      p.y += dy * dt;
      p.z += dz * dt;

      // 如果是第一个粒子且开启了追踪，记录轨迹
      if (idx === 0 && params.showTrace) {
        pathRef.current.push({ x: p.x, y: p.y, z: p.z });
        if (pathRef.current.length > 600) pathRef.current.shift();
      }

      const screenPos = getScreenPos(p.x, p.y, p.z, params.type, width, height);

      ctx.beginPath();
      ctx.arc(screenPos.x, screenPos.y, 1.2, 0, Math.PI * 2);
      ctx.fillStyle = p.color;
      ctx.fill();
    });

    // 绘制主粒子的连续轨迹
    if (params.showTrace && pathRef.current.length > 2) {
      ctx.beginPath();
      ctx.lineWidth = 1.8;
      const colors = PALETTES[params.palette];
      ctx.strokeStyle = colors[0];
      ctx.lineJoin = 'round';
      ctx.lineCap = 'round';

      pathRef.current.forEach((pt, i) => {
        const pos = getScreenPos(pt.x, pt.y, pt.z, params.type, width, height);
        if (i === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });

      // 添加发光效果
      ctx.shadowBlur = 10;
      ctx.shadowColor = colors[0];
      ctx.stroke();
      ctx.shadowBlur = 0;
    }

    requestRef.current = requestAnimationFrame(draw);
  }, [params]);

  // 坐标转换辅助函数
  const getScreenPos = (x: number, y: number, z: number, type: string, width: number, height: number) => {
    let scale = height / 60;
    let offsetX = width / 2;
    let offsetY = height / 2;

    if (type === 'aizawa') {
      scale = height / 4.2;
      offsetY = height * 0.65;
    } else if (type === 'dadras') {
      scale = height / 18;
    } else if (type === 'thomas') {
      scale = height / 10;
    } else if (type === 'lorenz') {
      scale = height / 65;
      offsetY = height * 0.85;
    }

    return {
      x: offsetX + x * scale,
      y: offsetY - (type === 'lorenz' || type === 'aizawa' ? z : y) * scale
    };
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [draw]);

  return <canvas ref={canvasRef} className="w-full h-full block" />;
};

export default SimulationCanvas;

import React from 'react';
import { SimulationParams, PaletteName, PALETTES, SimulationType } from '../types';

interface Props {
  params: SimulationParams;
  onUpdateParams: (newParams: Partial<SimulationParams>) => void;
  isAILoading: boolean;
}

interface Preset {
  label: string;
  params: Partial<SimulationParams>;
}

const PRESETS: Record<SimulationType, Preset[]> = {
  lorenz: [
    { label: '经典蝴蝶', params: { rho: 28, sigma: 10, beta: 8/3, speed: 1.0 } },
    { label: '收敛吸引', params: { rho: 14, sigma: 10, beta: 8/3, speed: 0.8 } },
    { label: '高能湍流', params: { rho: 45.92, sigma: 10, beta: 8/3, speed: 1.2 } }
  ],
  aizawa: [
    { label: '有机宝石', params: { mu: 0.35, speed: 1.0 } },
    { label: '核心塌缩', params: { mu: 0.1, speed: 0.6 } },
    { label: '流体飞溅', params: { mu: 0.7, speed: 1.4 } }
  ],
  dadras: [
    { label: '四翼星团', params: { mu: 3.0, speed: 1.0 } },
    { label: '紧致质点', params: { mu: 1.0, speed: 0.7 } },
    { label: '膨胀星系', params: { mu: 8.0, speed: 1.3 } }
  ],
  thomas: [
    { label: '标准迷宫', params: { mu: 0.2081, speed: 1.0 } },
    { label: '有序网格', params: { mu: 0.15, speed: 0.8 } },
    { label: '高熵晶格', params: { mu: 0.35, speed: 1.2 } }
  ]
};

const ControlPanel: React.FC<Props> = ({ params, onUpdateParams, isAILoading }) => {
  const models: { id: SimulationType; label: string; desc: string }[] = [
