             </button>
             <button 
               onClick={() => onUpdateParams({ mode: 'auto' })}
               className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${params.mode === 'auto' ? 'bg-indigo-600 shadow-sm text-white' : 'text-slate-400'}`}
